{
 "level": "A1‚ÄìA2",
 "intro": "In this topic you will learn <strong>three articles</strong> of the English language: <strong>a</strong>, <strong>an</strong> and <strong>the</strong> - when to use them and when to do without them.",
 "rules": [
 {
 "label": "A / An",
 "color": "emerald",
 "text": "<strong>Indefinite article</strong> - something general or new:",
 "example": "I saw a dog. / She is an engineer."
 },
 {
 "label": "The",
 "color": "blue",
 "text": "<strong>Definite article</strong> is something specific or known:",
 "example": "The dog was big. / The sun is bright."
 },
 {
 "label": "Zero (√ò)",
 "color": "amber",
 "text": "<strong>No article</strong> - general concepts, plural:",
 "example": "I love music. / Dogs are loyal."
 }
 ]
}

{
 "title": "1. Three types of articles",
 "intro": "In the English language, there are three ways to use articles:",
 "items": [
 {
 "label": "A / An",
 "title": "Indefinite",
 "subtitle": "Indefinite article ‚Äî something new or general (a book, an apple)"
 },
 {
 "label": "The",
 "title": "Definite",
 "subtitle": "Definite article ‚Äî something specific or known (the book I bought)"
 },
 {
 "label": "Zero √ò",
 "title": "No article",
 "subtitle": "Zero article ‚Äî abstract concepts, general plural (I love music)"
 }
 ]
}

{
 "title": "2. A vs An - when which?",
 "sections": [
 {
 "label": "A - before a consonant SOUND",
 "color": "emerald",
 "description": "The article <strong>a</strong> is used before words that <strong>begin with a consonant sound</strong>.",
 "examples": [
 {
 "en": "a book, a car, a dog",
 "ua": "a book, a car, a dog"
 },
 {
 "en": "a university [juÀên…™Ààv…úÀês…™ti]",
 "ua": "a university [juÀên…™Ààv…úÀês…™ti]"
 },
 {
 "en": "a European country",
 "ua": "a European country"
 },
 {
 "en": "a one-way street",
 "ua": "a one-way street"
 }
 ]
 },
 {
 "label": "An",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "an apple, an egg, an idea",
 "ua": "an apple, an egg, an idea"
 },
 {
 "en": "an hour [a ä…ô]",
 "ua": "an hour [a ä…ô]"
 },
 {
 "en": "an honest person",
 "ua": "an honest person"
 },
 {
 "en": "an MBA degree",
 "ua": "an MBA degree"
 }
 ]
 },
 {
 "label": "Important!",
 "color": "amber",
 "description": "Choosing a/an depends on the <strong>SOUND</strong>, not the letter!",
 "examples": [
 {
 "en": "a uniform (sound [j])",
 "ua": "a uniform (sound [j])"
 },
 {
 "en": "an umbrella (sound [ å])",
 "ua": "an umbrella (sound [ å])"
 }
 ],
 "note": "üìå Look at pronunciation, not spelling!"
 }
 ]
}

{
 "title": "3. When to use A / An",
 "sections": [
 {
 "label": "New or unspecified",
 "color": "emerald",
 "description": "Use <strong>a/an</strong> when you mention something for the first time or do not specify exactly which one.",
 "examples": [
 {
 "en": "I saw a cat in the garden.",
 "ua": "I saw a cat in the garden."
 },
 {
 "en": "She bought a new dress.",
 "ua": "She bought a new dress."
 },
 {
 "en": "There is a problem.",
 "ua": "There is a problem."
 }
 ]
 },
 {
 "label": "Professions and roles",
 "color": "sky",
 "description": "Use <strong>a/an</strong> when you name one person by profession, role or status.",
 "examples": [
 {
 "en": "She is a doctor.",
 "ua": "She is a doctor."
 },
 {
 "en": "He is an engineer.",
 "ua": "He is an engineer."
 },
 {
 "en": "I'm a student.",
 "ua": "I'm a student."
 }
 ]
 },
 {
 "label": "One of many",
 "color": "amber",
 "description": "Use <strong>a/an</strong> when you mean one representative of a larger group.",
 "examples": [
 {
 "en": "A dog is a loyal animal.",
 "ua": "A dog is a loyal animal."
 },
 {
 "en": "I need a pen.",
 "ua": "I need a pen."
 }
 ],
 "note": "A/An can mean one, one example, or any one of that kind."
 }
 ]
}

{
 "title": "4. When to use THE",
 "sections": [
 {
 "label": "Known or mentioned before",
 "color": "blue",
 "description": "Use <strong>the</strong> when the listener knows which person or thing you mean, or when you have already mentioned it.",
 "examples": [
 {
 "en": "I saw a cat. The cat was black.",
 "ua": "I saw a cat. The cat was black."
 },
 {
 "en": "Where is the bathroom?",
 "ua": "Where is the bathroom?"
 },
 {
 "en": "Did you read the book I gave you?",
 "ua": "Did you read the book I gave you?"
 }
 ]
 },
 {
 "label": "Unique in this context",
 "color": "sky",
 "description": "Use <strong>the</strong> when there is only one in the world, in the situation, or in the shared context.",
 "examples": [
 {
 "en": "the sun, the moon, the Earth",
 "ua": "the sun, the moon, the Earth"
 },
 {
 "en": "the Internet, the radio",
 "ua": "the Internet, the radio"
 },
 {
 "en": "the President of Ukraine",
 "ua": "the President of Ukraine"
 }
 ]
 },
 {
 "label": "With defining information",
 "color": "purple",
 "description": "Use <strong>the</strong> when extra words make the noun specific: with <em>of</em>, a relative clause, or a clear description.",
 "examples": [
 {
 "en": "the capital of France",
 "ua": "the capital of France"
 },
 {
 "en": "the man in the red jacket",
 "ua": "the man in the red jacket"
 },
 {
 "en": "the book that you recommended",
 "ua": "the book that you recommended"
 }
 ]
 },
 {
 "label": "Some geography and place names",
 "color": "amber",
 "description": "Use <strong>the</strong> with some countries, rivers, seas, mountain ranges and groups of islands.",
 "examples": [
 {
 "en": "the USA, the UK, the Netherlands",
 "ua": "the USA, the UK, the Netherlands"
 },
 {
 "en": "the Pacific Ocean, the Dnipro",
 "ua": "the Pacific Ocean, the Dnipro"
 },
 {
 "en": "the Alps, the Carpathians",
 "ua": "the Alps, the Carpathians"
 }
 ],
 "note": "The points to something specific, known or defined."
 }
 ]
}

{
 "title": "5. When NOT to use the article (Zero Article)",
 "sections": [
 {
 "label": "General concepts / abstractions",
 "color": "amber",
 "description": "When we talk about something <strong>in general</strong>, abstract concepts.",
 "examples": [
 {
 "en": "I love music.",
 "ua": "I love music."
 },
 {
 "en": "Life is beautiful.",
 "ua": "Life is beautiful."
 },
 {
 "en": "Money is not everything.",
 "ua": "Money is not everything."
 }
 ]
 },
 {
 "label": "Plural nouns in general statements",
 "color": "sky",
 "description": "When we talk about <strong>plurality in general</strong>.",
 "examples": [
 {
 "en": "Dogs are loyal animals.",
 "ua": "Dogs are loyal animals."
 },
 {
 "en": "I like cats.",
 "ua": "I like cats."
 },
 {
 "en": "Books are expensive.",
 "ua": "Books are expensive."
 }
 ]
 },
 {
 "label": "Countries, cities, names",
 "color": "emerald",
 "description": "Most <strong>proper names</strong> do not need an article.",
 "examples": [
 {
 "en": "Ukraine, Kyiv, London",
 "ua": "Ukraine, Kyiv, London"
 },
 {
 "en": "Mount Everest, Lake Baikal",
 "ua": "Mount Everest, Lake Baikal"
 },
 {
 "en": "John, Maria",
 "ua": "John, Maria"
 }
 ]
 },
 {
 "label": "Stable expressions",
 "color": "purple",
 "description": "In many <strong>regular expressions</strong> have no article.",
 "examples": [
 {
 "en": "at home, at work, at school",
 "ua": "at home, at work, at school"
 },
 {
 "en": "by bus, by car, by plane",
 "ua": "by bus, by car, by plane"
 },
 {
 "en": "go to bed, have breakfast",
 "ua": "go to bed, have breakfast"
 }
 ]
 }
 ]
}

{
 "title": "6. Comparison table",
 "intro": "Main cases of article use:",
 "rows": [
 {
 "en": "First mention",
 "ua": "First mention",
 "note": "A/An: I saw a dog."
 },
 {
 "en": "Known / mentioned",
 "ua": "Known / mentioned",
 "note": "The: The dog was big."
 },
 {
 "en": "Unique things",
 "ua": "Unique things",
 "note": "The: the sun, the moon"
 },
 {
 "en": "Professions",
 "ua": "Professions",
 "note": "A/An: She is a teacher."
 },
 {
 "en": "General / abstract",
 "ua": "General / abstract",
 "note": "√ò: I love music."
 },
 {
 "en": "Plural in general",
 "ua": "Plural in general",
 "note": "√ò: Dogs are loyal."
 }
 ],
 "warning": "üìå <strong>A/An</strong> = new, one of many. <strong>The</strong> = specific, known. <strong>√ò</strong> = general concept."
}

{
 "title": "7. Special cases",
 "sections": [
 {
 "label": "The + adjective = group of people",
 "color": "purple",
 "description": "<strong>The + adjective</strong> means a group of people.",
 "examples": [
 {
 "en": "the rich, the poor",
 "ua": "the rich, the poor"
 },
 {
 "en": "the young, the elderly",
 "ua": "the young, the elderly"
 },
 {
 "en": "the unemployed",
 "ua": "the unemployed"
 }
 ]
 },
 {
 "label": "Musical instruments",
 "color": "sky",
 "description": "With musical instruments we use <strong>the</strong>.",
 "examples": [
 {
 "en": "play the piano",
 "ua": "play the piano"
 },
 {
 "en": "play the guitar",
 "ua": "play the guitar"
 },
 {
 "en": "play the violin",
 "ua": "play the violin"
 }
 ]
 },
 {
 "label": "Time of day",
 "color": "amber",
 "description": "With the time of day: <strong>in the morning/afternoon/evening</strong>, but At night</strong>. Common mistakes",
 "examples": [
 {
 "en": "in the morning",
 "ua": "in the morning"
 },
 {
 "en": "in the afternoon",
 "ua": "in the afternoon"
 },
 {
 "en": "at night",
 "ua": "at night"
 }
 ]
 }
 ]
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Omission of the article before the profession.",
 "wrong": "She is doctor.",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">She is a doctor.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "A instead of An before a vowel sound.",
 "wrong": "a hour, an honest person",
 "right": "‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã"
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "The with abstract concepts.",
 "wrong": "The life is beautiful.",
 "right": "‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã Ukraine."
 },
 {
 "label": "Mistake 4",
 "color": "purple",
 "title": "Using an article before most country names.",
 "wrong": "I live in the Ukraine.",
 "right": " ‚úÖ <span class=\"font-mono\">I live in Ukraine.</span>"
 }
 ]
}

{
 "title": "10. Practice",
 "select_title": "Exercise 1. Choose the correct article",
 "select_intro": "Fill in the blanks with the article a, an, the or √ò (without an article).",
 "selects": [
 {
 "label": "She is ___ engineer. (a / an / the / √ò)",
 "prompt": "Which article?"
 },
 {
 "label": "I saw ___ sun today. (a / an / the / √ò)",
 "prompt": "Which article?"
 },
 {
 "label": "___ dogs are loyal animals. (a / an / the / √ò)",
 "prompt": "Which article?"
 },
 {
 "label": "I need ___ hour to finish. (a / an / the / √ò)",
 "prompt": "Which article?"
 }
 ],
 "options": [
 "a",
 "an",
 "the",
 "√ò"
 ],
 "input_title": "Exercise 2. Choose a or an",
 "input_intro": "Write a or an before the word.",
 "inputs": [
 {
 "before": "___ university",
 "after": "‚Üí"
 },
 {
 "before": "___ honest answer",
 "after": "‚Üí"
 },
 {
 "before": "___ European country",
 "after": "‚Üí"
 }
 ],
 "rephrase_title": "Exercise 3. Correct the error",
 "rephrase_intro": "Find and correct the error with the article.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "He is a teacher.",
 "example_target": "He is a teacher."
 },
 {
 "original": "1. I love the music.",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. She lives in France. / Any ‚Äî Quantity",
 "placeholder": "Fix the mistake"
 }
 ]
}

